import{_ as a,c as s,o as e,V as n}from"./chunks/framework.FCm07Aw3.js";const m=JSON.parse('{"title":"WoW Macros","description":"","frontmatter":{},"headers":[],"relativePath":"misc/wow-macros.md","filePath":"misc/wow-macros.md"}'),t={name:"misc/wow-macros.md"},i=n(`<h1 id="wow-macros" tabindex="-1">WoW Macros <a class="header-anchor" href="#wow-macros" aria-label="Permalink to &quot;WoW Macros&quot;">​</a></h1><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ul><li><a href="#general">General</a></li><li><a href="#priest">Priest</a></li><li><a href="#paladin">Paladin</a></li><li><a href="#druid">Druid</a></li><li><a href="#shaman">Shaman</a></li></ul><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h2><h3 id="fishing" tabindex="-1">fishing <a class="header-anchor" href="#fishing" aria-label="Permalink to &quot;fishing&quot;">​</a></h3><p>Equip fishing gear and use specific items for fishing. Alt-modifier uses additional fishing tools.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip Fishing</span></span>
<span class="line"><span>/equip [noequipped:Fishing Pole] Seth&#39;s Graphite Fishing Pole</span></span>
<span class="line"><span>/equip Lucky Fishing Hat</span></span>
<span class="line"><span>/use [mod:alt] Aquadynamic Fish Attractor</span></span>
<span class="line"><span>/use [mod:alt] Sharpened Fish Hook</span></span>
<span class="line"><span>/use [mod:alt] 16</span></span>
<span class="line"><span>/click StaticPopup1Button1</span></span>
<span class="line"><span>/cast Fishing</span></span></code></pre></div><h3 id="flying-and-ground-mount" tabindex="-1">flying and ground mount <a class="header-anchor" href="#flying-and-ground-mount" aria-label="Permalink to &quot;flying and ground mount&quot;">​</a></h3><p>Summons different mounts based on the flyable status of the area.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>/cast [flyable] Swift Purple Gryphon</span></span>
<span class="line"><span>/cast [noflyable] Swift White Ram</span></span>
<span class="line"><span>/cast [noflyable] Amani War Bear</span></span>
<span class="line"><span>/cast [noflyable] Reins of the Swift Mistsaber</span></span></code></pre></div><h3 id="targeting-and-using-offensive-spells" tabindex="-1">targeting and using offensive spells <a class="header-anchor" href="#targeting-and-using-offensive-spells" aria-label="Permalink to &quot;targeting and using offensive spells&quot;">​</a></h3><h4 id="melee" tabindex="-1">melee <a class="header-anchor" href="#melee" aria-label="Permalink to &quot;melee&quot;">​</a></h4><p>Clears dead/help targets and casts spell, initiating attack.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cleartarget [dead][help]</span></span>
<span class="line"><span>/cast insert_whatever_offensive_spell</span></span>
<span class="line"><span>/startattack</span></span></code></pre></div><h4 id="range" tabindex="-1">range <a class="header-anchor" href="#range" aria-label="Permalink to &quot;range&quot;">​</a></h4><p>Clears target conditions and tragets the nearest enemy if not already having a target casts spell.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cleartarget [dead][help]</span></span>
<span class="line"><span>/targetenemy [noexists]</span></span>
<span class="line"><span>/cast insert_whatever_offensive_spell</span></span></code></pre></div><h3 id="basic-healer-macro" tabindex="-1">basic healer macro <a class="header-anchor" href="#basic-healer-macro" aria-label="Permalink to &quot;basic healer macro&quot;">​</a></h3><p>Macro casts a friendly beneficial spell based on conditions: Alt modifier self-casts (@player), mouseover targets (@mouseover), or applies to the target&#39;s friendly (@targettarget,help) if applicable.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cast [mod:alt,@player][@mouseover,help,nodead][help][@targettarget,help,nodead][] insert_whatever_spell</span></span></code></pre></div><h3 id="wand" tabindex="-1">wand <a class="header-anchor" href="#wand" aria-label="Permalink to &quot;wand&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cast !Shoot</span></span></code></pre></div><h3 id="runes" tabindex="-1">runes <a class="header-anchor" href="#runes" aria-label="Permalink to &quot;runes&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/use Demonic Rune</span></span>
<span class="line"><span>/use Dark Rune</span></span></code></pre></div><h3 id="healthstones" tabindex="-1">healthstones <a class="header-anchor" href="#healthstones" aria-label="Permalink to &quot;healthstones&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/use item:22105</span></span>
<span class="line"><span>/use item:22104</span></span>
<span class="line"><span>/use item:22103</span></span>
<span class="line"><span>/use Major Healthstone</span></span></code></pre></div><h2 id="priest" tabindex="-1">Priest <a class="header-anchor" href="#priest" aria-label="Permalink to &quot;Priest&quot;">​</a></h2><h3 id="dispel" tabindex="-1">dispel <a class="header-anchor" href="#dispel" aria-label="Permalink to &quot;dispel&quot;">​</a></h3><p>This macro interrupts casting and casts Dispel Magic. Ctrl triggers Mass Dispel. Alt dispel player. Shift dispel the target of the current target if it is an enemy. Dispels magic based on mouseover conditions - helping friendly targets or dispelling harmful magic from enemies.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/stopcasting</span></span>
<span class="line"><span>/cast [mod:ctrl] Mass Dispel;[mod:alt,@player][mod:shift,@targettarget,nodead] [@mouseover,help,nodead][@mouseover,harm,nodead][] Dispel Magic</span></span></code></pre></div><h3 id="flash-heal" tabindex="-1">flash heal <a class="header-anchor" href="#flash-heal" aria-label="Permalink to &quot;flash heal&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cast [@mouseover,help,nodead][help][@targettarget,help,nodead][] Flash Heal</span></span></code></pre></div><h3 id="shield" tabindex="-1">shield <a class="header-anchor" href="#shield" aria-label="Permalink to &quot;shield&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/stopcasting</span></span>
<span class="line"><span>/cast [mod:alt,@player][@mouseover,help,nodead][help][@targettarget,help,nodead][] Power Word: Shield</span></span></code></pre></div><h3 id="mind-flay" tabindex="-1">mind flay <a class="header-anchor" href="#mind-flay" aria-label="Permalink to &quot;mind flay&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cast [harm,nodead,nochanneling] Mind Flay</span></span></code></pre></div><h2 id="paladin" tabindex="-1">Paladin <a class="header-anchor" href="#paladin" aria-label="Permalink to &quot;Paladin&quot;">​</a></h2><h3 id="crusader-strike" tabindex="-1">crusader strike <a class="header-anchor" href="#crusader-strike" aria-label="Permalink to &quot;crusader strike&quot;">​</a></h3><p>Clears dead/help targets and casts Crusader Strike, initiating attack.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cleartarget [dead][help]</span></span>
<span class="line"><span>/cast Crusader Strike</span></span>
<span class="line"><span>/startattack</span></span></code></pre></div><h3 id="avengers-shield-cleanse" tabindex="-1">avengers shield + cleanse <a class="header-anchor" href="#avengers-shield-cleanse" aria-label="Permalink to &quot;avengers shield + cleanse&quot;">​</a></h3><p>Casts Cleanse or Avenger&#39;s Shield based on modifiers.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cast [mod:alt,@player][@mouseover,help,nodead][help,nodead] Cleanse; [harm,nodead][] Avenger&#39;s Shield</span></span></code></pre></div><h2 id="druid" tabindex="-1">Druid <a class="header-anchor" href="#druid" aria-label="Permalink to &quot;Druid&quot;">​</a></h2><h3 id="faerie-fire" tabindex="-1">faerie Fire <a class="header-anchor" href="#faerie-fire" aria-label="Permalink to &quot;faerie Fire&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cast [form:1/3,@mouseover,harm][form:1/3] Faerie Fire (Feral)(); [@mouseover,harm][] Faerie Fire</span></span></code></pre></div><h3 id="forms" tabindex="-1">Forms <a class="header-anchor" href="#forms" aria-label="Permalink to &quot;Forms&quot;">​</a></h3><h4 id="travel-form" tabindex="-1">Travel Form <a class="header-anchor" href="#travel-form" aria-label="Permalink to &quot;Travel Form&quot;">​</a></h4><p>Switches between Aquatic Form and Travel Form based on swimming status.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cancelform [noform:2/4]</span></span>
<span class="line"><span>/cast [swimming] Aquatic Form; [noswimming] Travel Form</span></span></code></pre></div><h4 id="bear-cat" tabindex="-1">Bear, Cat <a class="header-anchor" href="#bear-cat" aria-label="Permalink to &quot;Bear, Cat&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip Dire Bear Form</span></span>
<span class="line"><span>/cancelform [noform:0]</span></span>
<span class="line"><span>/use [mod:shift] 13</span></span>
<span class="line"><span>/cast Dire Bear Form(Shapeshift)</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip Cat Form</span></span>
<span class="line"><span>/cancelform</span></span>
<span class="line"><span>/cast Cat Form(Shapeshift)</span></span></code></pre></div><h4 id="caster" tabindex="-1">Caster <a class="header-anchor" href="#caster" aria-label="Permalink to &quot;Caster&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cancelform</span></span>
<span class="line"><span>/stopcasting</span></span></code></pre></div><h3 id="prowl-pounce" tabindex="-1">prowl + pounce <a class="header-anchor" href="#prowl-pounce" aria-label="Permalink to &quot;prowl + pounce&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cast [nostealth] Prowl; Pounce</span></span></code></pre></div><h2 id="shaman" tabindex="-1">Shaman <a class="header-anchor" href="#shaman" aria-label="Permalink to &quot;Shaman&quot;">​</a></h2><h3 id="lightning-bolt" tabindex="-1">lightning bolt <a class="header-anchor" href="#lightning-bolt" aria-label="Permalink to &quot;lightning bolt&quot;">​</a></h3><p>Clears target conditions and casts Lightning Bolt on a new enemy if one isn&#39;t targeted already.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cleartarget [dead][help]</span></span>
<span class="line"><span>/targetenemy [noexists]</span></span>
<span class="line"><span>/cast Lightning Bolt</span></span></code></pre></div><h3 id="earth-shock" tabindex="-1">earth shock <a class="header-anchor" href="#earth-shock" aria-label="Permalink to &quot;earth shock&quot;">​</a></h3><p>Interrupts casting and casts Earth Shock. Ctrl+Shift targets focus, Shift+Mouseover harms, using Rank 1. Otherwise, casts Earth Shock on hostile mouseover targets.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/stopcasting</span></span>
<span class="line"><span>/cast [mod:ctrl,@focus][mod:shift,@mouseover,harm,exists,nodead][mod:shift] Earth Shock(Rank 1); [@mouseover,harm,exists,nodead][] Earth Shock</span></span></code></pre></div><h3 id="chain-heal" tabindex="-1">Chain Heal <a class="header-anchor" href="#chain-heal" aria-label="Permalink to &quot;Chain Heal&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cast [@mouseover,help,nodead] [help][@targettarget,help,nodead][] Chain Heal</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cast [mod:shift,@mouseover,help,nodead][mod:shift,help][mod:shift,@targettarget,help,nodead][mod:shift] Chain Heal(Rank 4); [@mouseover,help,nodead] [help][@targettarget,help,nodead][] Chain Heal(Rank 2)</span></span></code></pre></div><h3 id="purge-cure-disease-cure-poison" tabindex="-1">Purge + Cure Disease + Cure Poison <a class="header-anchor" href="#purge-cure-disease-cure-poison" aria-label="Permalink to &quot;Purge + Cure Disease + Cure Poison&quot;">​</a></h3><p>When the target is an enemy, it triggers Purge. If the target is friendly, it adapts: Shift+Alt cleanses the player of diseases, Shift+@mouseover or not cleanses friendlies. Alt cleanses poisons on the player, @mouseover or not cleanses poison of friendlies.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cast [mod:shift+alt,@player][mod:shift,@mouseover,help,nodead][mod:shift,help,nodead] Cure Disease;[mod:alt,@player][@mouseover,help,nodead][help,nodead] Cure Poison; [mod:shift,@targettarget,harm,nodead][@mouseover,harm,nodead][] Purge</span></span></code></pre></div><h3 id="totems" tabindex="-1">Totems <a class="header-anchor" href="#totems" aria-label="Permalink to &quot;Totems&quot;">​</a></h3><h4 id="air" tabindex="-1">air <a class="header-anchor" href="#air" aria-label="Permalink to &quot;air&quot;">​</a></h4><p>Summons different totems based on modifier combinations: Shift+Alt for Nature Resistance Totem, Alt+Ctrl for Tranquil Air Totem, Alt for Grounding Totem, Ctrl for Wrath of Air Totem, Shift for Windfury Totem, and Grace of Air Totem by default.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cast [mod:alt+shift] Nature Resistance Totem; [mod:alt+ctrl] Tranquil Air Totem; [mod:alt] Grounding Totem; [mod:ctrl] Wrath of Air Totem; [mod:shift] Windfury Totem; Grace of Air Totem</span></span></code></pre></div><h4 id="earth" tabindex="-1">earth <a class="header-anchor" href="#earth" aria-label="Permalink to &quot;earth&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cast [mod:alt+ctrl] Earth Elemental Totem; [mod:alt] Tremor Totem; [mod:ctrl] Stoneclaw Totem; [mod:shift] Earthbind Totem; Strength of Earth Totem</span></span></code></pre></div><h4 id="fire" tabindex="-1">fire <a class="header-anchor" href="#fire" aria-label="Permalink to &quot;fire&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cast [mod:alt+shift] Frost Resistance Totem; [mod:alt+ctrl] Fire Elemental Totem; [mod:ctrl] Magma Totem; [mod:shift] Fire Nova Totem; Searing Totem</span></span></code></pre></div><h4 id="water" tabindex="-1">water <a class="header-anchor" href="#water" aria-label="Permalink to &quot;water&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#showtooltip</span></span>
<span class="line"><span>/cast [mod:alt+shift] Fire Resistance Totem; [mod:alt+ctrl] Mana Tide Totem; [mod:alt] Healing Stream Totem; [mod:ctrl] Disease Cleansing Totem; [mod:shift] Poison Cleansing Totem; Mana Spring Totem</span></span></code></pre></div><h4 id="wf-goa" tabindex="-1">wf/goa <a class="header-anchor" href="#wf-goa" aria-label="Permalink to &quot;wf/goa&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>/castsequence reset=3 Windfury Totem, Grace of Air Totem</span></span></code></pre></div>`,82),l=[i];function o(p,r,h,c,d,u){return e(),s("div",null,l)}const b=a(t,[["render",o]]);export{m as __pageData,b as default};
